package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import org.junit.jupiter.api.Test;

public class JsonElementTest {

  @Test
  public void testGetAsJsonArray_whenIsJsonArrayTrue_returnsThisAsJsonArray() {
    JsonElement element = mock(JsonElement.class);
    when(element.isJsonArray()).thenReturn(true);
    when(element.toString()).thenReturn("mockedJsonArray");
    // Cast to JsonArray for return
    JsonArray jsonArray = mock(JsonArray.class);
    // Use a spy to allow casting this to JsonArray
    JsonElement spyElement = spy(element);
    doReturn(true).when(spyElement).isJsonArray();

    // We have to mock the cast by returning the spy casted to JsonArray
    // but since spyElement is a JsonElement mock, cast is unchecked
    // So we override getAsJsonArray on spy to call real method to test it
    // Instead, create a subclass for testing

    JsonElement testElement = new JsonArray() {
      @Override
      public boolean isJsonArray() {
        return true;
      }
    };

    JsonArray result = testElement.getAsJsonArray();
    assertSame(testElement, result);
  }

  @Test
  public void testGetAsJsonArray_whenIsJsonArrayFalse_throwsIllegalStateException() {
    JsonElement element = new JsonElement() {
      @Override
      public boolean isJsonArray() {
        return false;
      }

      @Override
      public JsonElement deepCopy() {
        return null;
      }

      @Override
      public String toString() {
        return "notJsonArrayElement";
      }
    };

    IllegalStateException thrown = assertThrows(IllegalStateException.class, element::getAsJsonArray);
    assertEquals("Not a JSON Array: notJsonArrayElement", thrown.getMessage());
  }
}
